{
  "schema_version": "patch_intent.v1",
  "intents": [
    {
      "intent_id": "fix_fixture_template_files",
      "operation": "replace-once",
      "target": {
        "target_file_guess": ".claude/skills/deterministic-markdown-patcher2/templates/fixture_spec.template.json",
        "frontmatter_required": false
      },
      "hints": {
        "nearby_phrases": [
          "\"files\": ["
        ],
        "symbol_or_section_names": [
          "fixture_spec files array"
        ]
      },
      "replacement": {
        "content": "\"files\": [\n    {\n      \"path\": \"patch_intent.json\",\n      \"content\": \"Fixture-owned sample intent\"\n    },\n    {\n      \"path\": \"patch_policy.json\",\n      \"content\": \"{}\"\n    },",
        "content_role": "span_replacement",
        "preserve_surrounding_formatting": true
      },
      "validation": {
        "expected_phrases": [
          "\"path\": \"patch_intent.json\"",
          "\"path\": \"patch_policy.json\"",
          "Fixture-owned sample intent"
        ],
        "forbidden_phrases": [
          "\"files\": [\n    {\n      \"path\": \"docs/example.md\""
        ]
      },
      "safety": {
        "require_unique_match": true,
        "fail_on_ambiguity": true,
        "allow_full_file_rewrite": false,
        "max_files_touched": 1
      },
      "notes": "Fixture representative for inserting patch_intent.json and patch_policy.json file entries before docs/example.md."
    }
  ]
}

{
  "schema_version": "patch_intent.v1",
  "intents": [
    {
      "intent_id": "make_python_validation_optional",
      "operation": "replace-once",
      "target": {
        "target_file_guess": ".claude/skills/deterministic-markdown-patcher2/templates/patch_policy.template.json",
        "frontmatter_required": false
      },
      "hints": {
        "nearby_phrases": [
          "\"required\": true"
        ],
        "symbol_or_section_names": [
          "json_parse_templates validation command"
        ]
      },
      "replacement": {
        "content": "\"required\": false",
        "content_role": "span_replacement",
        "preserve_surrounding_formatting": true
      },
      "validation": {
        "expected_phrases": [
          "\"required\": false"
        ],
        "forbidden_phrases": [
          "\"required\": true"
        ]
      },
      "safety": {
        "require_unique_match": true,
        "fail_on_ambiguity": true,
        "allow_full_file_rewrite": false,
        "max_files_touched": 1
      },
      "notes": "The template currently marks a Python validation command as required, but patch_executor.py rejects validation subprocesses except git, rg, and yq. This repair makes the example command non-blocking without widening executor subprocess policy."
    }
  ]
}
